@app.get("/")
def index():
    visits = g.session.get("visits", 0) + 1
    g.session["visits"] = visits
    return jsonify(
        {
            "message": "Flask app with Redis session storage and caching",
            "session_id": g.session_id,
            "visits": visits,
        }
    )


@app.post("/login")
def login():
    payload = request.get_json(silent=True) or {}
    username = payload.get("username")
    if not username:
        return jsonify({"error": "username is required"}), 400

    g.session["user"] = {"username": username, "logged_in": True}
    return jsonify({"message": "logged in", "session_id": g.session_id, "user": g.session["user"]})


@app.post("/logout")
def logout():
    redis_client.delete(session_key(g.session_id))
    g.session = {}
    response = make_response(jsonify({"message": "logged out"}))
    response.delete_cookie(SESSION_COOKIE_NAME)
    return response


@app.get("/session")
def session_info():
    return jsonify({"session_id": g.session_id, "session": g.session})


@app.get("/profile/<int:user_id>")
def profile(user_id):
    profile_data = get_user_profile(user_id)
    return jsonify({"cached_profile": profile_data})


@app.get("/health")
def health():
    try:
        pong = redis_client.ping()
        return jsonify({"status": "ok", "redis": pong})
    except redis.RedisError as exc:
        return jsonify({"status": "error", "error": str(exc)}), 500


